#include <stdio.h>
#include <stdlib.h>
int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int X, Y, D; scanf("%d %d %d", &X, &Y, &D);
        int diff = abs(X - Y);
        if (diff <= D) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

